	// Start workers
	for i := 0; i < workerCount; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for item := range itemChan {
				// Create a new VM for each evaluation to ensure isolation
				workerVM := otto.New()

				// Set a timeout to prevent infinite loops
				workerVM.Interrupt = make(chan func(), 1)
				go func() {
