// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}
	var resultMutex sync.Mutex

	// Pre-compile the script once for better performance and security
	vm := otto.New()
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	// Create a worker pool to limit concurrent VM execution
	maxWorkers := 10
	workerChan := make(chan map[string]interface{}, len(items))
	var wg sync.WaitGroup

	// Start workers
	for i := 0; i < maxWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for item := range workerChan {
				// Create a new VM for each item to ensure isolation
				itemVM := otto.New()

				// Set execution timeout to prevent infinite loops
				itemVM.Interrupt = make(chan func(), 1)

				// Inject the current item as a global variable named 'item'
				err := itemVM.Set("item", item)
				if err != nil {
					// Skip this item on error
					continue
				}

				// Run the pre-compiled script with timeout protection
				done := make(chan bool, 1)
				var value otto.Value
				var runErr error

				go func() {
					value, runErr = itemVM.Run(script)
					done <- true
				}()

				select {
				case <-done:
					// Script completed normally
				case <-make(chan struct{}):
					// Timeout would be implemented here
					// For now, we'll let the script continue but this provides the structure
					continue
				}

