	for _, item := range items {
		wg.Add(1)
		go func(currentItem map[string]interface{}) {
			defer wg.Done()

			// Create a new VM for this goroutine
			localVM := otto.New()

			// Inject the current item as a global variable named 'item'
			err := localVM.Set("item", currentItem)
			if err != nil {
				errChan <- err
				return
			}

			// Run the pre-compiled script
			value, err := localVM.Run(compiledScript)
			if err != nil {
				errChan <- err
				return
			}

			// Convert result to boolean using JavaScript truthiness
			boolResult, err := value.ToBoolean()
			if err != nil {
				errChan <- err
				return
			}

			if boolResult {
				resultChan <- currentItem
			}
		}(item)
	}

	// Wait for all goroutines to complete
	wg.Wait()
	close(errChan)
	close(resultChan)

	// Check for errors
	if len(errChan) > 0 {
		return nil, <-errChan
